func NewLink(connType string, host string, crypt bool, compress bool, remoteAddr string, localProxy bool, opts ...Option) *Link {
	options := newOptions(opts...)

	return &Link{
		RemoteAddr:	remoteAddr,
		ConnType:	connType,
		Host:		host,
		Crypt:		crypt,
		Compress:	compress,
		LocalProxy:	localProxy,
		Option:		options,
	}
}
